import React from 'react';
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  BarChart,
  Bar,
  Cell,
  PieChart,
  Pie,
  LineChart,
  Line,
  ScatterChart,
  Scatter,
  ZAxis
} from 'recharts';
import { MetricPoint, CompetitorData } from '../types';

interface TrendChartProps {
  data: MetricPoint[];
  dataKey: string;
  color: string;
  showForecast?: boolean;
}

export const TrendChart: React.FC<TrendChartProps> = ({ data, dataKey, color, showForecast }) => {
  return (
    <ResponsiveContainer width="100%" height={250}>
      <AreaChart data={data} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
        <defs>
          <linearGradient id={`color${dataKey}`} x1="0" y1="0" x2="0" y2="1">
            <stop offset="5%" stopColor={color} stopOpacity={0.8}/>
            <stop offset="95%" stopColor={color} stopOpacity={0}/>
          </linearGradient>
        </defs>
        <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{fontSize: 10}} />
        <YAxis axisLine={false} tickLine={false} tick={{fontSize: 10}} />
        <CartesianGrid vertical={false} strokeDasharray="3 3" stroke="#f0f0f0" />
        <Tooltip 
          contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
        />
        <Area 
          type="monotone" 
          dataKey="value" 
          stroke={color} 
          fillOpacity={1} 
          fill={`url(#color${dataKey})`} 
          name="数值"
        />
        {showForecast && (
             <Area 
             type="monotone" 
             dataKey="forecast" 
             stroke={color} 
             strokeDasharray="5 5"
             fill="none"
             name="预测值"
           />
        )}
      </AreaChart>
    </ResponsiveContainer>
  );
};

export const MultiLineChart: React.FC<{data: any[], lines: any[]}> = ({ data, lines }) => {
  return (
    <ResponsiveContainer width="100%" height={250}>
      <LineChart data={data}>
        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
        <XAxis dataKey="date" tick={{fontSize: 10}} />
        <YAxis tick={{fontSize: 10}} />
        <Tooltip />
        <Legend />
        {lines.map((line) => (
          <Line key={line.key} type="monotone" dataKey={line.key} stroke={line.color} strokeWidth={2} name={line.name} dot={{r: 3}} />
        ))}
      </LineChart>
    </ResponsiveContainer>
  );
};

export const TieringMatrixChart: React.FC<{data: any[]}> = ({ data }) => {
  return (
    <ResponsiveContainer width="100%" height={250}>
      <ScatterChart margin={{ top: 20, right: 20, bottom: 20, left: 20 }}>
        <CartesianGrid strokeDasharray="3 3" />
        <XAxis type="number" dataKey="value" name="当前消耗" unit="$" label={{ value: '消耗', position: 'insideBottom', offset: -10 }} />
        <YAxis type="number" dataKey="potential" name="增长潜力" unit="%" label={{ value: '潜力', angle: -90, position: 'insideLeft' }} />
        <ZAxis type="category" dataKey="name" name="客户" />
        <Tooltip cursor={{ strokeDasharray: '3 3' }} />
        <Scatter name="客户分层" data={data} fill="#6366f1">
